using System;
using System.Linq;
using System.Reflection;
using Xunit;

namespace TestProject.Tests;

/// <summary>
/// Tests for <c>TestProject.Configuration.FileServiceOptions</c>, the
/// strongly-typed options object bound from the "FileService" configuration
/// section that configures the server-side home directory.
///
/// This type was relocated from the root <c>TestProject</c> namespace into
/// <c>TestProject.Configuration</c>. Because the type's full name changes as a
/// result of that move, these tests resolve the type by <strong>reflection</strong>
/// against the main assembly rather than via a direct C# reference. This keeps the
/// file compilable both before and after the relocation, while the assertions pin
/// down the expected end state:
/// <list type="bullet">
/// <item>The type lives in <c>TestProject.Configuration</c> (and only there).</item>
/// <item>It is a public class with a public parameterless constructor and a
/// mutable <c>string HomeDirectory</c> property defaulting to <c>"Home"</c>.</item>
/// </list>
/// The behaviors themselves are unchanged by the move; these tests verify the type
/// arrives at its new home with its contract intact, and that no duplicate
/// root-namespace definition lingers.
/// </summary>
public class FileServiceOptionsTests
{
    private const string ExpectedFullName = "TestProject.Configuration.FileServiceOptions";
    private const string ExpectedNamespace = "TestProject.Configuration";
    private const string ExpectedRootFullName = "TestProject.FileServiceOptions";
    private const string HomeDirectoryProperty = "HomeDirectory";

    // Program is declared in the root TestProject namespace and is unaffected by
    // the move, so it is a stable anchor for obtaining the main assembly.
    private static Assembly MainAssembly => typeof(Program).Assembly;

    /// <summary>
    /// Resolves <c>FileServiceOptions</c> by its fully-qualified name, asserting
    /// that it exists in the <c>TestProject.Configuration</c> namespace.
    /// </summary>
    private static Type GetOptionsType()
    {
        var type = MainAssembly.GetType(ExpectedFullName);
        Assert.NotNull(type);
        return type!;
    }

    // =====================================================================
    // Type identity / namespace placement
    // =====================================================================

    [Fact]
    public void FileServiceOptions_LivesInTestProjectConfigurationNamespace()
    {
        var type = GetOptionsType();

        Assert.Equal(ExpectedNamespace, type.Namespace);
        Assert.Equal(ExpectedFullName, type.FullName);
    }

    [Fact]
    public void FileServiceOptions_NoLongerDeclaredInRootTestProjectNamespace()
    {
        // The old root-namespace definition must be gone. If it lingers alongside
        // the new one, the two become ambiguous and DI resolution is unreliable.
        var rootType = MainAssembly.GetType(ExpectedRootFullName);

        Assert.Null(rootType);
    }

    [Fact]
    public void Assembly_DeclaresExactlyOne_FileServiceOptions_Type()
    {
        var matches = MainAssembly.GetTypes()
            .Where(t => t.Name == "FileServiceOptions")
            .ToArray();

        var fullNames = string.Join(", ", matches.Select(t => t.FullName));

        Assert.True(matches.Length == 1,
            $"Expected exactly one FileServiceOptions type, but found {matches.Length}: [{fullNames}].");
        Assert.Equal(ExpectedFullName, matches[0].FullName);
    }

    [Fact]
    public void FileServiceOptions_IsAPublicNonAbstractClass()
    {
        var type = GetOptionsType();

        Assert.True(type.IsClass);
        Assert.True(type.IsPublic);
        Assert.False(type.IsAbstract);
    }

    // =====================================================================
    // HomeDirectory contract (unchanged by the move)
    // =====================================================================

    [Fact]
    public void Constructor_DefaultHomeDirectory_IsHome()
    {
        var type = GetOptionsType();
        var instance = Activator.CreateInstance(type);

        Assert.NotNull(instance);
        var value = type.GetProperty(HomeDirectoryProperty)!.GetValue(instance);

        Assert.Equal("Home", value);
    }

    [Theory]
    [InlineData("MyFiles")]
    [InlineData("/var/data/files")]
    [InlineData("Data/Files")]
    [InlineData("")]
    [InlineData("   ")]
    public void HomeDirectory_RoundTripsArbitraryStringValues(string value)
    {
        var type = GetOptionsType();
        var prop = type.GetProperty(HomeDirectoryProperty);

        Assert.NotNull(prop);
        var instance = Activator.CreateInstance(type);
        Assert.NotNull(instance);

        prop!.SetValue(instance, value);

        Assert.Equal(value, prop.GetValue(instance));
    }

    [Fact]
    public void HomeDirectory_IsPublicMutableStringProperty()
    {
        var type = GetOptionsType();
        var prop = type.GetProperty(HomeDirectoryProperty);

        Assert.NotNull(prop);
        Assert.Equal(typeof(string), prop!.PropertyType);
        Assert.True(prop.CanRead, "HomeDirectory must have a getter.");
        Assert.True(prop.CanWrite, "HomeDirectory must have a setter.");
        Assert.True(prop.GetGetMethod(nonPublic: false) is not null,
            "HomeDirectory getter must be public.");
        Assert.True(prop.GetSetMethod(nonPublic: false) is not null,
            "HomeDirectory setter must be public.");
    }

    [Fact]
    public void FileServiceOptions_HasParameterlessPublicConstructor()
    {
        var type = GetOptionsType();

        var ctor = type.GetConstructor(Type.EmptyTypes);

        Assert.NotNull(ctor);
        Assert.True(ctor!.IsPublic);
    }
}

using System;
using System.IO;
using System.Linq;
using System.Text.RegularExpressions;
using Xunit;

namespace TestProject.Tests;

/// <summary>
/// Verifies the file-level mechanics of relocating
/// <c>FileServiceOptions</c> from the root <c>TestProject</c> namespace into
/// <c>TestProject.Configuration</c>.
///
/// These tests inspect source files directly (rather than compiling against the
/// relocated type) so they remain compilable both before and after the move. The
/// assertions describe the expected end state of the repository:
/// <list type="bullet">
/// <item>The old <c>FileServiceOptions.cs</c> at the repository root is deleted.</item>
/// <item>A new <c>Configuration/FileServiceOptions.cs</c> exists and declares
/// <c>namespace TestProject.Configuration;</c>.</item>
/// <item><c>Program.cs</c> references the new namespace via a <c>using</c>
/// directive or a fully-qualified name, and no longer uses the old root-qualified
/// type name.</item>
/// <item><c>Services/FileService.cs</c> references the new namespace so its
/// <c>IOptions&lt;FileServiceOptions&gt;</c> constructor parameter resolves.</item>
/// </list>
/// </summary>
public class FileServiceOptionsNamespaceTests
{
    // File-scoped namespace declarations the relocation is expected to produce/consume.
    private const string ConfigurationUsingPattern = @"using\s+TestProject\.Configuration\s*;";
    private const string FullyQualifiedPattern = @"TestProject\.Configuration\.FileServiceOptions";
    // Matches the OLD root-qualified name. This deliberately does NOT match
    // "TestProject.Configuration.FileServiceOptions" because a '.' (not
    // '.FileServiceOptions') follows "TestProject".
    private const string OldRootQualifiedPattern = @"TestProject\.FileServiceOptions\b";

    /// <summary>
    /// Walks up from the test output directory to the folder containing
    /// <c>TestProject.csproj</c> (and <c>Program.cs</c>), which is the repo root.
    /// </summary>
    private static string RepoRoot
    {
        get
        {
            var dir = new DirectoryInfo(AppContext.BaseDirectory);
            while (dir is not null)
            {
                if (File.Exists(Path.Combine(dir.FullName, "TestProject.csproj")) &&
                    File.Exists(Path.Combine(dir.FullName, "Program.cs")))
                {
                    return dir.FullName;
                }

                dir = dir.Parent;
            }

            throw new DirectoryNotFoundException(
                "Could not locate the repository root (folder containing both " +
                "TestProject.csproj and Program.cs) by walking up from " +
                AppContext.BaseDirectory + ".");
        }
    }

    private static string ReadSource(string relativePath) =>
        File.ReadAllText(Path.Combine(RepoRoot, relativePath));

    // =====================================================================
    // File relocation: old file removed, new file present
    // =====================================================================

    [Fact]
    public void OldRootLevel_FileServiceOptions_File_IsDeleted()
    {
        var oldPath = Path.Combine(RepoRoot, "FileServiceOptions.cs");

        Assert.False(File.Exists(oldPath),
            $"The old root-level '{oldPath}' must be deleted because the type " +
            "now lives under Configuration/FileServiceOptions.cs.");
    }

    [Fact]
    public void New_Configuration_FileServiceOptions_File_Exists()
    {
        var newPath = Path.Combine(RepoRoot, "Configuration", "FileServiceOptions.cs");

        Assert.True(File.Exists(newPath),
            "Expected Configuration/FileServiceOptions.cs to exist after the move.");
    }

    [Fact]
    public void New_Configuration_File_DeclaresTestProjectConfigurationNamespace()
    {
        var newPath = Path.Combine(RepoRoot, "Configuration", "FileServiceOptions.cs");
        Assert.True(File.Exists(newPath),
            "Cannot verify namespace: Configuration/FileServiceOptions.cs is missing.");

        var source = File.ReadAllText(newPath);

        // File-scoped namespace declaration as specified by the task.
        Assert.Matches(
            @"namespace\s+TestProject\.Configuration\s*;",
            source);

        // The new file must NOT declare the old root namespace.
        Assert.DoesNotMatch(
            @"namespace\s+TestProject\s*\{",
            source);
        Assert.DoesNotMatch(
            @"namespace\s+TestProject\s*;",
            source);
    }

    [Fact]
    public void New_Configuration_File_DeclaresTheHomeDirectoryClass()
    {
        var newPath = Path.Combine(RepoRoot, "Configuration", "FileServiceOptions.cs");
        Assert.True(File.Exists(newPath));

        var source = File.ReadAllText(newPath);

        Assert.Matches(@"public\s+class\s+FileServiceOptions\b", source);
        Assert.Matches(@"HomeDirectory\b", source);
    }

    [Fact]
    public void Repo_ContainsExactlyOne_FileServiceOptions_SourceFile()
    {
        // Build artifact directories must be ignored; only the handwritten source counts.
        var all = Directory.GetFiles(RepoRoot, "FileServiceOptions.cs", SearchOption.AllDirectories)
            .Where(p => !IsUnderBuildArtifacts(p))
            .ToArray();

        var relative = string.Join(", ", all.Select(p => Path.GetRelativePath(RepoRoot, p)));

        Assert.True(all.Length == 1,
            $"Expected exactly one FileServiceOptions.cs source file, found {all.Length}: [{relative}].");
        Assert.Equal(
            Path.Combine("Configuration", "FileServiceOptions.cs"),
            Path.GetRelativePath(RepoRoot, all[0]));
    }

    private static bool IsUnderBuildArtifacts(string fullPath)
    {
        var parts = fullPath.Split(Path.DirectorySeparatorChar, Path.AltDirectorySeparatorChar);
        return parts.Contains("bin") || parts.Contains("obj");
    }

    // =====================================================================
    // Program.cs references the relocated namespace
    // =====================================================================

    [Fact]
    public void Program_ReferencesTestProjectConfigurationNamespace()
    {
        var source = ReadSource("Program.cs");

        var hasUsing = Regex.IsMatch(source, ConfigurationUsingPattern);
        var hasFullyQualified = Regex.IsMatch(source, FullyQualifiedPattern);

        Assert.True(hasUsing || hasFullyQualified,
            "Program.cs must reference TestProject.Configuration either via a " +
            "'using TestProject.Configuration;' directive or by using the " +
            "fully-qualified 'TestProject.Configuration.FileServiceOptions' name " +
            "in the Configure<FileServiceOptions>(...) call.");
    }

    [Fact]
    public void Program_DoesNotReferenceOldRootQualifiedType()
    {
        var source = ReadSource("Program.cs");

        Assert.DoesNotMatch(OldRootQualifiedPattern, source);
    }

    // =====================================================================
    // Services/FileService.cs references the relocated namespace
    // =====================================================================

    [Fact]
    public void FileService_ReferencesTestProjectConfigurationNamespace()
    {
        var source = ReadSource(Path.Combine("Services", "FileService.cs"));

        var hasUsing = Regex.IsMatch(source, ConfigurationUsingPattern);
        var hasFullyQualified = Regex.IsMatch(source, FullyQualifiedPattern);

        Assert.True(hasUsing || hasFullyQualified,
            "Services/FileService.cs must reference TestProject.Configuration " +
            "(its constructor takes IOptions<FileServiceOptions>) via a 'using " +
            "TestProject.Configuration;' directive or a fully-qualified name.");
    }
}

using System.Collections.Concurrent;
using System.Text;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.FileProviders;
using Microsoft.Extensions.Options;
using TestProject.Models;
using TestProject.Services;
using Xunit;

namespace TestProject.Tests.Services;

/// <summary>
/// Functional tests for <see cref="FileService"/>. Each test runs against a
/// unique temporary content root so that tests are fully independent and
/// never touch the real file system outside a scratch directory.
///
/// The service computes its home root once, at construction time, as
/// <c>Path.GetFullPath(Path.Combine(env.ContentRootPath, options.HomeDirectory))</c>.
/// Directory creation is deferred (lazy) until first use, so these tests
/// trigger an operation before asserting the directory exists on disk. Every
/// operation must funnel inputs through a path-safety check so that paths
/// escaping the home root throw <see cref="ArgumentException"/>.
/// </summary>
public class FileServiceTests : IDisposable
{
    private readonly string _contentRoot;

    public FileServiceTests()
    {
        _contentRoot = Directory.CreateTempSubdirectory("fs_test_").FullName;
    }

    public void Dispose()
    {
        try
        {
            Directory.Delete(_contentRoot, recursive: true);
        }
        catch
        {
            // Best effort cleanup; temp dirs may already be gone.
        }
    }

    // Builds a fresh service whose home directory lives under the per-test
    // content root. Returns the absolute, normalized root the service should
    // be treating as its sandbox.
    private (FileService service, string root) CreateService(string homeDirectory = "Home")
    {
        var env = new FakeWebHostEnvironment
        {
            ContentRootPath = _contentRoot
        };
        var options = Options.Create(new FileServiceOptions
        {
            HomeDirectory = homeDirectory
        });

        var service = new FileService(options, env);
        var root = Path.GetFullPath(Path.Combine(_contentRoot, homeDirectory));
        return (service, root);
    }

    private static IFormFile CreateFormFile(string fileName, string content)
    {
        var bytes = Encoding.UTF8.GetBytes(content);
        var stream = new MemoryStream(bytes);
        return new FormFile(stream, 0, bytes.Length, "file", fileName);
    }

    // =====================================================================
    // Constructor / root computation
    // =====================================================================

    [Fact]
    public void Constructor_CreatesRootDirectory_WhenItDoesNotExist()
    {
        var home = "BrandNewHome";
        var expectedRoot = Path.GetFullPath(Path.Combine(_contentRoot, home));

        Assert.False(Directory.Exists(expectedRoot));

        var (service, root) = CreateService(home);

        // Root creation is lazy: it happens on first use, not in the
        // constructor. Trigger initialization before asserting existence.
        service.ResolveFullPath("");

        Assert.True(Directory.Exists(root));
        Assert.Equal(expectedRoot, root);
    }

    [Fact]
    public void Constructor_SupportsNestedHomeDirectoryPath()
    {
        var home = "Data/Files";
        var expectedRoot = Path.GetFullPath(Path.Combine(_contentRoot, home));

        Assert.False(Directory.Exists(expectedRoot));

        var (service, root) = CreateService(home);

        // Root creation is lazy: trigger initialization (which must create
        // the full nested path) before asserting existence.
        service.ResolveFullPath("");

        Assert.Equal(expectedRoot, root);
        Assert.True(Directory.Exists(root));
    }

    [Fact]
    public void Constructor_NullHomeDirectory_DefaultsToHome()
    {
        var env = new FakeWebHostEnvironment { ContentRootPath = _contentRoot };
        var options = Options.Create(new FileServiceOptions { HomeDirectory = null! });

        var service = new FileService(options, env);

        var expected = Path.GetFullPath(Path.Combine(_contentRoot, "Home"));
        // ResolveFullPath triggers lazy initialization, materializing the
        // default "Home" directory before we assert its existence.
        Assert.Equal(expected, service.ResolveFullPath(""));
        Assert.True(Directory.Exists(expected));
    }

